#include <iostream>using namespace std; int main(){    ios::sync_with_stdio(0);    cin.tie(0);        int f[1000001]={};    int n,q;    cin>>n>>q;        for(int i=0;i<n;i++)    {        int x;        cin>>x;        f[x]++;    }        while(q--)    {        int k;        cin>>k;        if(k>0)        {            f[k]++;        }        else        {            int t=-k;            int i=1;            while(1)            {                if(f[i]>=t)                {                    f[i]--;                    break;                }                t-=f[i];                i++;            }        }    }        for(int i=1;i<=1000000;i++)    {        if(f[i])        {            cout<<i;            return 0;        }    }    cout<<0;    return 0;}